(function () {
  "use strict";

  // voorkom dubbel runnen
  if (window.__ddoSugarCandyWidgetLoaded) return;
  window.__ddoSugarCandyWidgetLoaded = true;

  function setImp(el, prop, value) {
    el.style.setProperty(prop, value, "important");
  }

  function slugGuardMount() {
    // Mount alleen als #sugarsize bestaat
    var h = document.querySelector("#sugarsize");
    if (!h) return null;

    // voorkom dubbele render als loader ooit opnieuw injecteert
    if (h.dataset.widgetMounted === "1") return null;
    h.dataset.widgetMounted = "1";
    return h;
  }

  var h = slugGuardMount();
  if (!h) return;

  var R = {
    Basic: { XS:"60F,G,H,I/65F,G,H", S:"60J,K/65I,J,K/70F,G,H,I", M:"70J,K/75F,G,H,I", L:"75J,K/80F,G,H,I", XL:"80J,K/85F,G,H,I", "2X":"85J,K/90F,G,H,I", "3XL":"90J/95E,F,G,H", "4XL":"95I/100E,F,G,H" },
    Nurse: {},
    Posh: { XS:"60G,H,I/65G,H", S:"60J,K/65I,J,K/70G,H,I", M:"70J,K/75G,H,I", L:"75J,K/80G,H,I", XL:"80J,K/85G,H,I", XXL:"85J,K/90G,H,I" },
    Bestie: { XXS:"60K,L,M", XS:"65K,L,M", S:"70K,L,M", M:"75K,L,M", L:"80K,L,M", XL:"85K,L,M" }
  };
  R.Nurse = R.Basic;

  var U = "AA,A,B,C,D,E,F,G,H,I,J,K,L,M".split(",");

  function fillSelect(sel, arr) {
    sel.innerHTML = "";
    for (var i2 = 0; i2 < arr.length; i2++) {
      var o = document.createElement("option");
      o.value = arr[i2];
      o.textContent = arr[i2];
      sel.appendChild(o);
    }
  }

  function parseSeg(seg) {
    seg = seg.trim();
    var j = 0;
    while (j < seg.length && seg.charCodeAt(j) >= 48 && seg.charCodeAt(j) <= 57) j++;
    if (!j || j >= seg.length) return null;
    return {
      b: parseInt(seg.slice(0, j), 10),
      c: seg.slice(j).split(",").map(function (x) { return x.trim().toUpperCase(); })
    };
  }

  function segments(model) {
    var r = R[model], out = [];
    for (var k in r) {
      String(r[k]).split("/").forEach(function (s) {
        s = s.trim();
        if (!s) return;
        var p = parseSeg(s);
        if (p) out.push({ z: k, b: p.b, c: p.c });
      });
    }
    return out;
  }

  function bands(model) {
    var seen = {}, a = [];
    segments(model).forEach(function (s) { seen[s.b] = 1; });
    for (var k in seen) a.push(+k);
    a.sort(function (x, y) { return x - y; });
    return a;
  }

  function cups(model, band) {
    var seen = {}, a = [];
    segments(model).forEach(function (s) {
      if (s.b === band) s.c.forEach(function (c) { seen[c] = 1; });
    });
    for (var k in seen) a.push(k);
    a.sort(function (x, y) { return U.indexOf(x) - U.indexOf(y); });
    return a;
  }

  function advise(model, band, cup) {
    var r = R[model], u = String(cup).toUpperCase();
    for (var k in r) {
      var g = String(r[k]).split("/");
      for (var i3 = 0; i3 < g.length; i3++) {
        var p = parseSeg(g[i3]);
        if (p && p.b === band && p.c.indexOf(u) > -1) return k;
      }
    }
    return "";
  }

  // bouw UI
  var f = document.createElement("form");
  var t = document.createElement("table");
  var th = document.createElement("thead");
  var tb = document.createElement("tbody");
  var trh = document.createElement("tr");

  ["Model", "Bandmaat", "Cupmaat", "Ons advies"].forEach(function (tx) {
    var thd = document.createElement("th");
    thd.textContent = tx;
    setImp(thd, "text-align", "unset");
    trh.appendChild(thd);
  });
  th.appendChild(trh);

  var tr = document.createElement("tr");
  var tdM = document.createElement("td"),
      tdB = document.createElement("td"),
      tdC = document.createElement("td"),
      tdA = document.createElement("td");

  var sM = document.createElement("select");
  ["Basic", "Nurse", "Posh", "Bestie"].forEach(function (v) {
    var o = document.createElement("option");
    o.value = v;
    o.textContent = v;
    sM.appendChild(o);
  });

  var sB = document.createElement("select");
  var sC = document.createElement("select");

  var adv = document.createElement("input");
  adv.type = "text";
  adv.readOnly = true;

  var w = (window.innerWidth < 420 ? "84px" : "100px");
  [sM, sB, sC, adv].forEach(function (el) {
    setImp(el, "width", w);
    setImp(el, "margin-right", "10px");
  });

  tdM.appendChild(sM);
  tdB.appendChild(sB);
  tdC.appendChild(sC);
  tdA.appendChild(adv);

  [tdM, tdB, tdC, tdA].forEach(function (td) { tr.appendChild(td); });
  tb.appendChild(tr);

  t.appendChild(th);
  t.appendChild(tb);

  var wrap = document.createElement("div");
  setImp(wrap, "overflow-x", "auto");
  wrap.style.webkitOverflowScrolling = "touch";
  wrap.appendChild(t);

  f.appendChild(wrap);

  // mount
  h.innerHTML = "";
  h.appendChild(f);

  function rebuildCups() {
    var m = sM.value, b = +sB.value, c = cups(m, b), pv = sC.value;
    fillSelect(sC, c);
    if (c.length) sC.value = c.indexOf(pv) > -1 ? pv : c[0];
  }

  function update() {
    var m = sM.value, b = +sB.value, c = sC.value;
    adv.value = (isFinite(b) && c) ? advise(m, b, c) : "";
  }

  function rebuildAll() {
    var m = sM.value, b = bands(m), prev = +sB.value || NaN;
    fillSelect(sB, b);
    if (b.length) sB.value = b.indexOf(prev) > -1 ? String(prev) : String(b[0]);
    rebuildCups();
    update();
  }

  sM.addEventListener("change", rebuildAll);
  sB.addEventListener("change", function () { rebuildCups(); update(); });
  sC.addEventListener("change", update);

  sM.value = "Basic";
  rebuildAll();
})();
